SELECT total_revenue, average_price
FROM analytics
WHERE date = '2023-01-01' AND item_id = 0 AND shop_id = 0;

SELECT SUM(total_revenue) AS total_revenue_generated
FROM analytics
WHERE date = '1' AND item_id = 1;

SELECT average_price, total_revenue
FROM analytics
WHERE date = '1';

SELECT item_id, total_revenue, average_price
FROM analytics
WHERE date = '2023-01-01' AND shop_id = 1;
